-- CNB Primaria - Matemáticas - Tercer y Cuarto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Matemáticas_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Tercer Grado
('Tercer Grado', 'Matemáticas', '1. Construye patrones y establece relaciones que le facilitan la interpretación de signos y señales utilizados para el desplazamiento en su comunidad y otros contextos.', ARRAY['1.1. Elabora instrucciones para orientar a compañeros y compañeras en la realización de juegos que impliquen seguimiento de patrones o desplazamientos.', '1.2. Descubre la secuencia numérica de patrones existentes en la naturaleza o en su entorno cultural.', '1.3. Interpreta las operaciones aritméticas implícitas en patrones.', '1.4. Identifica la relación causa-efecto en patrones presentes en el entorno natural, social o cultural.', '1.5. Elabora y describe patrones.']),
('Tercer Grado', 'Matemáticas', '2. Utiliza diferentes estrategias para representar los algoritmos y términos matemáticos en su entorno cultural, familiar, escolar y comunitario.', ARRAY['2.2. Utiliza el primer cuadrante del plano cartesiano para mostrar desplazamientos.']),
('Tercer Grado', 'Matemáticas', '3. Propone diferentes ideas y pensamientos con libertad y coherencia utilizando diferentes signos, símbolos gráficos, algoritmos y términos matemáticos.', ARRAY['3.1. Identifica diferentes tipos de conjuntos.', '3.2. Diferencia conjuntos iguales de equivalentes.', '3.3. Establece la diferencia entre la unión y la intersección de conjuntos.']),
('Tercer Grado', 'Matemáticas', '4. Aplica conocimientos y experiencias de aritmética básica en la interacción con su entorno familiar, escolar y comunitario.', ARRAY['4.1. Utiliza los números naturales en sistema decimal del 0 al 10,000 y en Sistema Vigesimal Maya hasta 7,999.', '4.3. Efectúa multiplicaciones y divisiones de números naturales menores que 100.', '4.4. Utiliza hasta dos fracciones para representar partes iguales de una unidad.']),
('Tercer Grado', 'Matemáticas', '5. Aplica conocimientos matemáticos en la sistematización de soluciones diversas a problemas de la vida cotidiana.', ARRAY['5.1. Recoge y ordena información.', '5.2. Aplica diferentes operaciones y estrategias en la solución de problemas.', '5.3. Predice eventos, sucesos y problemas.']),
('Tercer Grado', 'Matemáticas', '6. Utiliza la información que obtiene de las relaciones de diferentes elementos expresándolas en forma gráfica.', ARRAY['6.1. Explora elementos de figuras geométricas planas y sólidos geométricos.', '6.2. Calcula el perímetro de un triángulo y un cuadrilátero, de un cuadrado y un rectángulo.', '6.3. Identifica ejes de simetría en figuras geométricas planas y objetos.']),
('Tercer Grado', 'Matemáticas', '7. Aplica nuevos conocimientos a partir de nuevos modelos de la ciencia y la cultura.', ARRAY['7.1. Utiliza diferentes unidades de medida para establecer longitud.', '7.3. Utiliza diferentes unidades de medida para establecer capacidad.', '7.4. Utiliza otras unidades de medida propias de la región.', '7.5. Resuelve problemas que involucren el concepto de unidad monetaria nacional.', '7.6. Calcula el tiempo de duración de diferentes actividades que se realizan en la vida cotidiana.']),

-- Cuarto Grado
('Cuarto Grado', 'Matemáticas', '1. Relaciona formas, figuras geométricas, símbolos, signos y señales con diferentes objetos y fenómenos que acontecen en el contexto natural, social y cultural de su comunidad.', ARRAY['1.1. Clasifica y mide ángulos.', '1.2. Descubre el paralelismo y la perpendicularidad en diferentes objetos que observa en el aula y fuera de ella.', '1.3. Clasifica triángulos por la longitud de sus lados.', '1.4. Clasifica cuadriláteros por la relación de paralelismo o perpendicularidad entre sus lados opuestos y contiguos.', '1.5. Calcula perímetro de triángulos y cuadriláteros.', '1.6. Clasifica sólidos geométricos.', '1.8. Utiliza el primer cuadrante del plano cartesiano para ubicar puntos.', '1.9. Interpreta señales utilizadas en su cultura para el desplazamiento.']),
('Cuarto Grado', 'Matemáticas', '2. Utiliza el pensamiento lógico reflexivo, crítico y creativo para buscar respuesta a situaciones problemáticas de la vida escolar, familiar y comunitaria.', ARRAY['2.1. Descubre patrones geométricos o numéricos.']),
('Cuarto Grado', 'Matemáticas', '3. Utiliza signos, símbolos gráficos, algoritmos y términos matemáticos que le permiten manifestar ideas y pensamientos.', ARRAY['3.1. Utiliza diferentes representaciones para nombrar un conjunto.']),
('Cuarto Grado', 'Matemáticas', '4. Identifica elementos matemáticos que contribuyen al rescate, protección y conservación de su medio social, natural y cultural.', ARRAY['4.1. Utiliza los números naturales en el sistema decimal hasta 100,000, en el sistema vigesimal maya hasta la cuarta posición y en números romanos hasta cien.', '4.2. Determina los números pares e impares como subconjunto de los números naturales.', '4.3. Realiza cálculos de adición y sustracción en el conjunto de los números naturales, en un ámbito hasta 100,000.', '4.4. Realiza cálculos de multiplicación y división en el conjunto de los números naturales, en un ámbito hasta 100,000.', '4.5. Relaciona la multiplicación con la potenciación.', '4.6. Efectúa divisiones con divisor de dos dígitos.', '4.7. Resuelve problemas con operaciones de adición, sustracción, multiplicación o división.', '4.8. Efectúa sumas y restas con numeración maya.', '4.9. Utiliza los decimales para representar cantidades y calcular sumas y restas.', '4.10. Efectúa sumas y restas de fracciones.', '4.11. Utiliza las proporciones para resolver problemas.']),
('Cuarto Grado', 'Matemáticas', '5. Organiza en forma lógica procesos de distintas materias básicas en la solución de problemas de la vida cotidiana.', ARRAY['5.1. Utiliza operaciones con naturales y fracciones para la solución de problemas.', '5.2. Resuelve problemas que tienen varias o ninguna solución.', '5.3. Predice eventos, sucesos y problemas.']),
('Cuarto Grado', 'Matemáticas', '6. Expresa en forma gráfica y descriptiva la información que obtiene relacionada con diversos elementos y acontecimientos de su contexto social, cultural y natural.', ARRAY['6.1. Establece relación de dependencia entre dos eventos o sucesos.', '6.2. Registra información cuantitativa de hechos o sucesos de su comunidad.', '6.3. Representa gráficamente información recopilada.', '6.4. Interpreta información presentada por medio de tablas y gráficas estadísticas.']),
('Cuarto Grado', 'Matemáticas', '7. Establece relaciones entre los conocimientos y tecnologías, propias de su cultura y las de otras culturas.', ARRAY['7.1. Utiliza diferentes unidades de medida para calcular longitud.', '7.2. Reproduce dibujos a escala.', '7.3. Utiliza diferentes unidades para establecer peso, capacidad y temperatura.', '7.4. Calcula el tiempo de duración de diferentes actividades que se realizan en la vida cotidiana utilizando la hora, minuto y segundo.', '7.6. Utiliza las monedas en diferentes actividades.', '7.7. Resuelve problemas que involucren el uso de la moneda nacional y operaciones de suma, resta, multiplicación y división.']);
